@startuml
class NewsOverview {
    news: List<News>
    nextPageLink: FernUniInternalLink
    previousPageLink: FernUniInternalLink
}

class News {
    date: Date
    headline: Headline
    sections: List<String>
}

class Headline {
    text: String
    link: FernUniInternalLink
}

class Section {
    text: String
    links: List<FernUniInternalLink>
}

NewsOverview --> News : 1 .. n
News --> Headline : 1
News --> Section : 1
@enduml
